import * as react from 'react';
import * as react_jsx_runtime from 'react/jsx-runtime';

/**
 * Supported visual weights for the Dirham symbol SVG component.
 *
 * Because the Dirham symbol is not yet in standard fonts (until Unicode 18.0),
 * weight simulation is applied via SVG stroke to match surrounding text weight,
 * similar to how $, €, £ adapt to their font's weight.
 */
type DirhamWeight = "thin" | "extralight" | "light" | "regular" | "medium" | "semibold" | "bold" | "extrabold" | "black";

interface DirhamSymbolProps {
    /**
     * Size in logical pixels.
     * @default 24
     */
    size?: number;
    /**
     * Color of the symbol.
     * @default "currentColor" (falls back to #000)
     */
    color?: string;
    /**
     * Accessible label for screen readers.
     * @default "UAE Dirham"
     */
    accessibilityLabel?: string;
    /**
     * Visual weight of the symbol.
     * @default "regular"
     */
    weight?: DirhamWeight;
}
/**
 * React Native SVG-based UAE Dirham symbol.
 *
 * Requires `react-native-svg` as a peer dependency.
 *
 * @example
 * ```tsx
 * import { DirhamSymbol } from "dirham/react-native";
 *
 * <DirhamSymbol size={24} />
 * <DirhamSymbol size={32} color="#00A86B" weight="bold" />
 * ```
 */
declare function DirhamSymbolBase({ size, color, accessibilityLabel, weight, }: DirhamSymbolProps): react_jsx_runtime.JSX.Element;
declare const DirhamSymbol: react.MemoExoticComponent<typeof DirhamSymbolBase>;

interface DirhamPriceProps {
    /**
     * Numeric amount to display.
     */
    amount: number;
    /**
     * Locale string for number formatting.
     * @default "en-AE"
     */
    locale?: string;
    /**
     * Number of decimal places.
     * @default 2
     */
    decimals?: number;
    /**
     * Use ISO currency code (AED) instead of the symbol.
     * @default false
     */
    useCode?: boolean;
    /**
     * Number notation style.
     * @default "standard"
     */
    notation?: "standard" | "compact";
    /**
     * Size of the Dirham symbol.
     * @default 16
     */
    symbolSize?: number;
    /**
     * Visual weight of the SVG symbol.
     * @default "regular"
     */
    weight?: DirhamWeight;
    /**
     * Text color.
     * @default "#000"
     */
    color?: string;
    /**
     * Font size for the amount text.
     * @default 16
     */
    fontSize?: number;
    /**
     * Accessible label for screen readers.
     */
    accessibilityLabel?: string;
}
/**
 * React Native component for displaying formatted Dirham prices.
 *
 * @example
 * ```tsx
 * import { DirhamPrice } from "dirham/react-native";
 *
 * <DirhamPrice amount={1250} />
 * <DirhamPrice amount={500} locale="ar-AE" />
 * ```
 */
declare function DirhamPriceBase({ amount, locale, decimals, useCode, notation, symbolSize, weight, color, fontSize, accessibilityLabel, }: DirhamPriceProps): react_jsx_runtime.JSX.Element;
declare const DirhamPrice: react.MemoExoticComponent<typeof DirhamPriceBase>;

export { DirhamPrice, type DirhamPriceProps, DirhamSymbol, type DirhamSymbolProps };
